        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new MultiplePortfoliosAddedMessage();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[MultiplePortfoliosAddedMessage](sbeTemplateId=");
            builder.Append(MultiplePortfoliosAddedMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(MultiplePortfoliosAddedMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != MultiplePortfoliosAddedMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(MultiplePortfoliosAddedMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != MultiplePortfoliosAddedMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(MultiplePortfoliosAddedMessage.BlockLength);
            builder.Append("):");

            builder.Append("RequestId=");
            builder.Append(this.RequestId);
            builder.Append('|');
            builder.Append("NoPortfolios=[");
            var noPortfolios = this.NoPortfolios;
            if (noPortfolios.Count > 0)
            {
                var first = true;
                while (noPortfolios.HasNext)
                {
                    if (!first)
                    {
                        builder.Append(',');
                    }
                    first = false;
                    noPortfolios.Next().BuildString(builder);
                }
            }
            builder.Append("]");

            this.Limit = originalLimit;

        }
